import javafx.application.Application;
import javafx.beans.property.*;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.control.cell.PropertyValueFactory;
import javafx.scene.layout.HBox;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

// Model class for TableView
class Person {
    private final SimpleStringProperty name;
    private final SimpleIntegerProperty age;
    private final SimpleStringProperty email;

    Person(String name, int age, String email) {
        this.name = new SimpleStringProperty(name);
        this.age = new SimpleIntegerProperty(age);
        this.email = new SimpleStringProperty(email);
    }

    public String getName() { return name.get(); }
    public void setName(String value) { name.set(value); }
    public StringProperty nameProperty() { return name; }

    public int getAge() { return age.get(); }
    public void setAge(int value) { age.set(value); }
    public IntegerProperty ageProperty() { return age; }

    public String getEmail() { return email.get(); }
    public void setEmail(String value) { email.set(value); }
    public StringProperty emailProperty() { return email; }
}

public class ListViewTableViewExample extends Application {
    @Override
    public void start(Stage primaryStage) {
        VBox root = new VBox(20);
        root.setPadding(new Insets(20));
        root.setAlignment(Pos.CENTER);

        // 1. ListView
        System.out.println("=== ListView ===");
        ListView<String> listView = new ListView<>();
        listView.setPrefHeight(150);
        listView.setMaxWidth(250);

        // ObservableList for dynamic updates
        ObservableList<String> items = FXCollections.observableArrayList(
            "Apple", "Banana", "Orange", "Grape", "Strawberry"
        );
        listView.setItems(items);

        // Selection listener
        Label selectionLabel = new Label("Selected: None");
        listView.getSelectionModel().selectedItemProperty().addListener((obs, oldVal, newVal) -> {
            selectionLabel.setText("Selected: " + (newVal != null ? newVal : "None"));
        });

        // ListView controls
        TextField addField = new TextField();
        addField.setPromptText("Add item...");
        addField.setMaxWidth(150);

        Button addBtn = new Button("Add");
        addBtn.setOnAction(e -> {
            String text = addField.getText();
            if (!text.isEmpty()) {
                items.add(text);
                addField.clear();
            }
        });

        Button removeBtn = new Button("Remove");
        removeBtn.setOnAction(e -> {
            int index = listView.getSelectionModel().getSelectedIndex();
            if (index >= 0) {
                items.remove(index);
            }
        });

        HBox listControls = new HBox(10);
        listControls.setAlignment(Pos.CENTER);
        listControls.getChildren().addAll(addField, addBtn, removeBtn);

        // 2. TableView
        System.out.println("=== TableView ===");
        TableView<Person> tableView = new TableView<>();
        tableView.setPrefHeight(250);
        tableView.setMaxWidth(500);

        // Create columns
        TableColumn<Person, String> nameCol = new TableColumn<>("Name");
        nameCol.setCellValueFactory(new PropertyValueFactory<>("name"));
        nameCol.setPrefWidth(150);

        TableColumn<Person, Integer> ageCol = new TableColumn<>("Age");
        ageCol.setCellValueFactory(new PropertyValueFactory<>("age"));
        ageCol.setPrefWidth(100);

        TableColumn<Person, String> emailCol = new TableColumn<>("Email");
        emailCol.setCellValueFactory(new PropertyValueFactory<>("email"));
        emailCol.setPrefWidth(200);

        tableView.getColumns().addAll(nameCol, ageCol, emailCol);

        // Add data
        ObservableList<Person> people = FXCollections.observableArrayList(
            new Person("Alice", 25, "alice@email.com"),
            new Person("Bob", 30, "bob@email.com"),
            new Person("Charlie", 28, "charlie@email.com"),
            new Person("Diana", 22, "diana@email.com")
        );
        tableView.setItems(people);

        // TableView selection
        Label tableLabel = new Label("Selected: None");
        tableView.getSelectionModel().selectedItemProperty().addListener((obs, oldVal, newVal) -> {
            if (newVal != null) {
                tableLabel.setText("Selected: " + newVal.getName() + ", Age: " + newVal.getAge());
            } else {
                tableLabel.setText("Selected: None");
            }
        });

        // TableView controls
        TextField nameField = new TextField();
        nameField.setPromptText("Name");
        nameField.setMaxWidth(120);

        TextField ageField = new TextField();
        ageField.setPromptText("Age");
        ageField.setMaxWidth(80);

        TextField emailField = new TextField();
        emailField.setPromptText("Email");
        emailField.setMaxWidth(150);

        Button addPersonBtn = new Button("Add Person");
        addPersonBtn.setOnAction(e -> {
            try {
                String name = nameField.getText();
                int age = Integer.parseInt(ageField.getText());
                String email = emailField.getText();
                if (!name.isEmpty() && !email.isEmpty()) {
                    people.add(new Person(name, age, email));
                    nameField.clear();
                    ageField.clear();
                    emailField.clear();
                }
            } catch (NumberFormatException ex) {
                System.out.println("Invalid age!");
            }
        });

        Button removePersonBtn = new Button("Remove Person");
        removePersonBtn.setOnAction(e -> {
            Person selected = tableView.getSelectionModel().getSelectedItem();
            if (selected != null) {
                people.remove(selected);
            }
        });

        HBox personControls = new HBox(10);
        personControls.setAlignment(Pos.CENTER);
        personControls.getChildren().addAll(
            nameField, ageField, emailField, addPersonBtn, removePersonBtn
        );

        root.getChildren().addAll(
            new Label("--- ListView ---"),
            listView,
            selectionLabel,
            listControls,
            new Separator(),
            new Label("--- TableView ---"),
            tableView,
            tableLabel,
            personControls
        );

        Scene scene = new Scene(root, 600, 750);

        primaryStage.setTitle("ListView & TableView");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

