import javafx.application.Application;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.HBox;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

public class ListViewPractice extends Application {
    @Override
    public void start(Stage primaryStage) {
        VBox root = new VBox(15);
        root.setPadding(new Insets(20));
        root.setAlignment(Pos.CENTER);

        ObservableList<String> languages = FXCollections.observableArrayList(
            "Java", "Python", "C++", "JavaScript"
        );

        ListView<String> listView = new ListView<>(languages);
        listView.setPrefHeight(150);
        listView.setMaxWidth(200);

        Label selectionLabel = new Label("Selected: None");
        listView.getSelectionModel().selectedItemProperty().addListener((obs, oldVal, newVal) -> {
            selectionLabel.setText("Selected: " + (newVal != null ? newVal : "None"));
        });

        TextField addField = new TextField();
        addField.setPromptText("Enter language...");
        addField.setMaxWidth(150);

        Button addBtn = new Button("Add");
        addBtn.setOnAction(e -> {
            String text = addField.getText().trim();
            if (!text.isEmpty()) {
                languages.add(text);
                addField.clear();
            }
        });

        Button removeBtn = new Button("Remove Selected");
        removeBtn.setOnAction(e -> {
            int idx = listView.getSelectionModel().getSelectedIndex();
            if (idx >= 0) {
                languages.remove(idx);
            }
        });

        HBox controls = new HBox(10);
        controls.setAlignment(Pos.CENTER);
        controls.getChildren().addAll(addField, addBtn, removeBtn);

        root.getChildren().addAll(
            new Label("Programming Languages"),
            listView,
            selectionLabel,
            controls
        );

        Scene scene = new Scene(root, 400, 400);
        primaryStage.setTitle("ListView Practice");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}
